import{_ as a,o as r,c as i,a2 as t}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"Display Email","description":"","frontmatter":{"title":"Display Email"},"headers":[],"relativePath":"docs/fr/advertisers/display-email/index.md","filePath":"docs/fr/advertisers/display-email/index.md"}'),s={name:"docs/fr/advertisers/display-email/index.md"};function d(n,e,l,p,o,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="encart-newsletter-display-email" tabindex="-1">Encart Newsletter (Display Email) <a class="header-anchor" href="#encart-newsletter-display-email" aria-label="Permalink to &quot;Encart Newsletter (Display Email)&quot;">​</a></h1><p>Insérez une bannière publicitaire au sein des communications d&#39;un partenaire. Un format de notoriété efficace et non intrusif.</p><div class="mt-4 mb-6"><a href="workflow" class="btn btn-primary fs-4 mr-2">Voir le Process</a><a href="specs" class="btn btn-outline fs-4">Specs Bannières</a></div><hr class="mb-6"><h2 class="text-blue-200 mb-4">Où diffuser votre bannière ?</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;margin-bottom:40px;width:100%;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 text-blue-200">📢 Blast (Newsletter Édito)</h3><p class="fs-2 text-grey-dk-000">Votre bannière s&#39;insère dans la newsletter hebdomadaire du média ou de l&#39;e-commerçant.</p><p class="mb-0 fs-2"><em>Ex: Header ou Cœur de contenu.</em></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 text-purple-200">🛍️ Post-Purchase (Transac)</h3><p class="fs-2 text-grey-dk-000">Votre bannière apparaît dans l&#39;email de confirmation de commande ou de livraison.</p><p class="mb-0 fs-2"><em>Ex: &quot;Profitez de cette offre partenaire en attendant votre colis&quot;.</em></p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);"><h3 class="mt-0 text-green-200">👋 Welcome Email</h3><p class="fs-2 text-grey-dk-000">Présence dans l&#39;email de bienvenue envoyé aux nouveaux inscrits.</p><p class="mb-0 fs-2"><em>Ex: Encart en bas de mail pour une offre complémentaire.</em></p></div></div><h2 class="text-grey-dk-000 mb-4">Pourquoi choisir ce format ?</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;min-width:250px;border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-soft);"><h3 class="mt-0 text-blue-200">⚡ Simplicité de Production</h3><p class="mb-0 text-grey-dk-000">Contrairement à l&#39;email dédié, <strong>vous ne fournissez qu&#39;une image</strong>. Pas besoin de coder un email HTML complet.</p></div><div style="flex:1;min-width:250px;border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-soft);"><h3 class="mt-0 text-purple-200">🛡️ Non Intrusif</h3><p class="mb-0 text-grey-dk-000">Votre marque s&#39;insère dans un contenu que l&#39;abonné attend, sans perturber sa lecture.</p></div></div><h2 class="text-blue-200 mb-4">Pourquoi passer par getinside ?</h2><div style="display:flex;flex-direction:column;gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🌐</div><div><h3 class="mt-0">Inventaire Unifié</h3><p class="fs-2 text-grey-dk-000 mb-0">Plus besoin de négocier avec chaque média ou e-commerçant. Accédez à un inventaire fragmenté de <strong>+250 partenaires</strong> via une seule plateforme.</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">🛡️</div><div><h3 class="mt-0">Brand Safety &amp; Contexte</h3><p class="fs-2 text-grey-dk-000 mb-0">Contrairement au Display programmatique (open web), votre marque s&#39;affiche ici dans un environnement <strong>fermé, sûr et cautionné</strong> par l&#39;éditeur (la marque partenaire).</p></div></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;background:var(--vp-c-bg-elv);display:flex;align-items:center;gap:20px;"><div style="font-size:32px;min-width:50px;text-align:center;">📊</div><div><h3 class="mt-0">Tracking Centralisé</h3><p class="fs-2 text-grey-dk-000 mb-0">Nous générons et uniformisons les liens de tracking pour toutes vos campagnes. Suivez les clics de 10 newsletters différentes sur un seul tableau de bord.</p></div></div></div>',10)])])}const u=a(s,[["render",d]]);export{v as __pageData,u as default};
